const sharedMem = new WebAssembly.Memory({
  initial: 10,
  shared: true
});
const worker = new Worker('worker.js');
worker.postMessage({ memory: sharedMem });

// worker.js
onmessage = async (e) => {
  const { memory } = e.data;
  const { instance } = await WebAssembly.instantiate(
    wasmBytes, { env: { memory } });
  // Her worker aynı belleği paylaşır
