## RAII
```cpp
// RAII wrapper
template<typename T>
class UniquePtr {
    T* ptr;
public:
    explicit UniquePtr(T* p) : ptr(p) {}
    ~UniquePtr() { delete ptr; }  // Otomatik serbest bırak
    T* get() { return ptr; }
    T& operator*() { return *ptr; }
    // Kopya yok, taşıma var
    UniquePtr(const UniquePtr&) = delete;
    UniquePtr(UniquePtr&& other) : ptr(other.ptr) { other.ptr = nullptr; }
};

// Kullanım: scope bitince otomatik delete
{
    UniquePtr<int> p(new int(42));
}  // ~UniquePtr çağrılır
```

## Rust Ownership Kuralları
