## Borrow Kuralları
```rust
fn main() {
    let mut data = vec![1, 2, 3];

    // Birden fazla değişmez referans OK
    let r1 = &data;
    let r2 = &data;
    println!("{} {}", r1[0], r2[0]);

    // Değişken referans: tek ve yalnız
    let r3 = &mut data;
    r3.push(4);
    // r1, r2 burada kullanılamaz → dangling olur

    // Interior mutability: RefCell
    use std::cell::RefCell;
    let data = RefCell::new(vec![1]);
    data.borrow_mut().push(2);  // Çalışma zamanı kontrol
}
```

